/**
 * Module dependencies.
 */

/**
 * Initialization middleware, exposing the request and response to each other,
 * as well as defaulting the X-Powered-By header field.
 *
 * @return {Function} middleware
 * @api private
 */

exports = module.exports = function() {
  return function expressInit(req, res, next) {
    // Set default response properties
    if (res.locals) {
      res.locals = Object.create(null);
    }

    // Set X-Powered-By header
    res.setHeader('X-Powered-By', 'Express');

    // Make request and response objects reference each other
    req.res = res;
    res.req = req;

    // Initialize response locals
    res.locals = res.locals || Object.create(null);

    // Continue middleware chain
    next();
  };
};